class Solution:
    def isValid(self, code):
        n = len(code)
        i = 0
        stack = []
        started = False
        while i < n:
            if not stack and started:
                return False
            if code[i] == '<':
                if i + 1 < n and code[i + 1] == '!':
                    if not stack:
                        return False
                    if code[i:i + 9] != '<![CDATA[':
                        return False
                    end = code.find(']]>', i + 9)
                    if end == -1:
                        return False
                    i = end + 3
                elif i + 1 < n and code[i + 1] == '/':
                    j = code.find('>', i)
                    if j == -1:
                        return False
                    name = code[i + 2:j]
                    if not (1 <= len(name) <= 9 and name.isupper() and name.isalpha()):
                        return False
                    if not stack or stack[-1] != name:
                        return False
                    stack.pop()
                    i = j + 1
                    if not stack:
                        if i != n:
                            return False
                        return True
                else:
                    j = code.find('>', i)
                    if j == -1:
                        return False
                    name = code[i + 1:j]
                    if not (1 <= len(name) <= 9 and name.isupper() and name.isalpha()):
                        return False
                    stack.append(name)
                    started = True
                    i = j + 1
            else:
                if not stack:
                    return False
                i += 1
        return started and not stack

