class Solution:
    def isValid(self, code):
        if not code or code[0] != '<':
            return False
        n = len(code)
        stack = []
        i = 0
        def valid_name(s):
            return 1 <= len(s) <= 9 and s.isalpha() and s.isupper()
        while i < n:
            if i > 0 and not stack:
                return False
            if code[i] == '<':
                if code.startswith('<![CDATA[', i):
                    if not stack:
                        return False
                    end = code.find(']]>', i + 9)
                    if end == -1:
                        return False
                    i = end + 3
                elif code.startswith('</', i):
                    j = code.find('>', i)
                    if j == -1:
                        return False
                    name = code[i + 2:j]
                    if not valid_name(name):
                        return False
                    if not stack or stack.pop() != name:
                        return False
                    i = j + 1
                else:
                    j = code.find('>', i)
                    if j == -1:
                        return False
                    name = code[i + 1:j]
                    if not valid_name(name):
                        return False
                    stack.append(name)
                    i = j + 1
            else:
                if not stack:
                    return False
                i += 1
        return not stack

