var isValid = function(code) {
    if (!code || code[0] !== '<') return false;
    const n = code.length;
    const stack = [];
    let i = 0;
    const validName = (s) => s.length >= 1 && s.length <= 9 && /^[A-Z]+$/.test(s);
    while (i < n) {
        if (i > 0 && stack.length === 0) return false;
        if (code[i] === '<') {
            if (code.startsWith('<![CDATA[', i)) {
                if (stack.length === 0) return false;
                const end = code.indexOf(']]>', i + 9);
                if (end === -1) return false;
                i = end + 3;
            } else if (code.startsWith('</', i)) {
                const j = code.indexOf('>', i);
                if (j === -1) return false;
                const name = code.slice(i + 2, j);
                if (!validName(name)) return false;
                if (stack.length === 0 || stack.pop() !== name) return false;
                i = j + 1;
            } else {
                const j = code.indexOf('>', i);
                if (j === -1) return false;
                const name = code.slice(i + 1, j);
                if (!validName(name)) return false;
                stack.push(name);
                i = j + 1;
            }
        } else {
            if (stack.length === 0) return false;
            i += 1;
        }
    }
    return stack.length === 0;
};
